const input = $input.first().json;
const ctx = $('Montar Prompt Ana').first().json;

if (input.error || !input.content) {
  return [{
    json: {
      ...ctx,
      mensagem: 'Oi! Tive uma instabilidade aqui. Pode repetir seu pedido? 🍕',
      acao: 'responder',
      carrinho: JSON.parse(ctx.carrinhoAtual ?? '{}'),
      encerrar_sessao: false
    }
  }];
}

const rawText = input.content?.[0]?.text ?? '{}';
let parsed;
try {
  const cleaned = rawText.replace(/```json?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    mensagem: 'Desculpe, tive um probleminha! Pode repetir? 🍕',
    acao: 'responder',
    carrinho: JSON.parse(ctx.carrinhoAtual ?? '{}'),
    encerrar_sessao: false
  };
}

const acoesValidas = ['responder','finalizar_pedido','escalar_humano','encerrar'];
if (!acoesValidas.includes(parsed.acao)) parsed.acao = 'responder';

return [{
  json: {
    ...ctx,
    mensagem: parsed.mensagem,
    acao: parsed.acao,
    carrinho: parsed.carrinho ?? JSON.parse(ctx.carrinhoAtual ?? '{}'),
    encerrar_sessao: parsed.encerrar_sessao ?? false
  }
}];

const { telefone, nome, carrinho, historico, texto, mensagem, acao, encerrar_sessao } = $input.first().json;

const novoHistorico = (historico + `\nCliente: ${texto}\nAna: ${mensagem}`).slice(-3000);
const status = (acao === 'encerrar' || encerrar_sessao) ? 'encerrada' : 'ativa';

return [{
  json: {
    telefone, nome, acao, encerrar_sessao,
    status,
    novoHistorico,
    carrinhoJson: JSON.stringify(carrinho),
    resumoPedido: acao === 'finalizar_pedido' ? montarResumoPedido(carrinho, nome, telefone) : ''
  }
}];

function montarResumoPedido(c, nome, tel) {
  if (!c || !c.itens || c.itens.length === 0) return `🍕 Pedido de ${nome} (${tel}) — carrinho vazio`;
  const linhas = c.itens.map(i => {
    const meia = i.metade2 ? ` / ${i.metade2}` : '';
    const borda = i.borda ? ` | Borda: ${i.borda}` : '';
    return `• ${i.qtd}x ${i.sabor}${meia}${borda} — R$${i.preco?.toFixed(2) ?? '?'}`;
  }).join('\n');
  const entrega = c.tipo_entrega === 'entrega' ? `🛵 Entrega: ${c.endereco}` : '🏠 Retirada no local';
  const pgto = c.pagamento ? `💳 Pagamento: ${c.pagamento}` : '💳 Pagamento: a confirmar';
  return `🍕 *PEDIDO NOVO*\nCliente: ${nome} (${tel})\n\n${linhas}\n\n${entrega}\n${pgto}\n💰 Total estimado: R$${(c.total ?? 0).toFixed(2)}`;
}
